import{_ as o,o as a,c as s,ai as d}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"智能体运行时","description":"","frontmatter":{"read_when":["更改智能体运行时、工作区引导或会话行为时"],"summary":"智能体运行时（嵌入式 pi-mono）、工作区契约和会话引导","title":"智能体运行时","x-i18n":{"generated_at":"2026-02-03T10:04:53Z","model":"claude-opus-4-5","provider":"pi","source_hash":"04b4e0bc6345d2afd9a93186e5d7a02a393ec97da2244e531703cb6a1c182325","source_path":"concepts/agent.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/agent.md","filePath":"zh-CN/concepts/agent.md","lastUpdated":1771906665000}'),c={name:"zh-CN/concepts/agent.md"};function t(n,e,l,i,p,r){return a(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="智能体运行时-🤖" tabindex="-1"><a class="header-anchor" href="#智能体运行时-🤖">#</a> 智能体运行时 🤖</h1><p>OpenSoul 运行一个源自 <strong>pi-mono</strong> 的嵌入式智能体运行时。</p><h2 id="工作区-必需" tabindex="-1"><a class="header-anchor" href="#工作区-必需">#</a> 工作区（必需）</h2><p>OpenSoul 使用单一智能体工作区目录（<code>agents.defaults.workspace</code>）作为智能体<strong>唯一</strong>的工作目录（<code>cwd</code>），用于工具和上下文。</p><p>建议：使用 <code>opensoul setup</code> 在缺失时创建 <code>~/.opensoul/opensoul.json</code> 并初始化工作区文件。</p><p>完整工作区布局 + 备份指南：<a href="/docs/concepts/agent-workspace">智能体工作区</a></p><p>如果启用了 <code>agents.defaults.sandbox</code>，非主会话可以在 <code>agents.defaults.sandbox.workspaceRoot</code> 下使用按会话隔离的工作区覆盖此设置（参见 <a href="/docs/gateway/configuration">Gateway 网关配置</a>）。</p><h2 id="引导文件-注入" tabindex="-1"><a class="header-anchor" href="#引导文件-注入">#</a> 引导文件（注入）</h2><p>在 <code>agents.defaults.workspace</code> 内，OpenSoul 期望以下用户可编辑的文件：</p><ul><li><code>AGENTS.md</code> — 操作指令 + &quot;记忆&quot;</li><li><code>SOUL.md</code> — 人设、边界、语气</li><li><code>TOOLS.md</code> — 用户维护的工具说明（例如 <code>imsg</code>、<code>sag</code>、约定）</li><li><code>BOOTSTRAP.md</code> — 一次性首次运行仪式（完成后删除）</li><li><code>IDENTITY.md</code> — 智能体名称/风格/表情</li><li><code>USER.md</code> — 用户档案 + 偏好称呼</li></ul><p>在新会话的第一轮，OpenSoul 将这些文件的内容直接注入智能体上下文。</p><p>空文件会被跳过。大文件会被修剪和截断并添加标记，以保持提示词精简（阅读文件获取完整内容）。</p><p>如果文件缺失，OpenSoul 会注入一行&quot;文件缺失&quot;标记（<code>opensoul setup</code> 将创建安全的默认模板）。</p><p><code>BOOTSTRAP.md</code> 仅在<strong>全新工作区</strong>（没有其他引导文件存在）时创建。如果你在完成仪式后删除它，后续重启不应重新创建。</p><p>要完全禁用引导文件创建（用于预置工作区），请设置：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skipBootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="内置工具" tabindex="-1"><a class="header-anchor" href="#内置工具">#</a> 内置工具</h2><p>核心工具（read/exec/edit/write 及相关系统工具）始终可用，受工具策略约束。<code>apply_patch</code> 是可选的，由 <code>tools.exec.applyPatch</code> 控制。<code>TOOLS.md</code> <strong>不</strong>控制哪些工具存在；它是关于<em>你</em>希望如何使用它们的指导。</p><h2 id="skills" tabindex="-1"><a class="header-anchor" href="#skills">#</a> Skills</h2><p>OpenSoul 从三个位置加载 Skills（名称冲突时工作区优先）：</p><ul><li>内置（随安装包提供）</li><li>托管/本地：<code>~/.opensoul/skills</code></li><li>工作区：<code>&lt;workspace&gt;/skills</code></li></ul><p>Skills 可通过配置/环境变量控制（参见 <a href="/docs/gateway/configuration">Gateway 网关配置</a> 中的 <code>skills</code>）。</p><h2 id="pi-mono-集成" tabindex="-1"><a class="header-anchor" href="#pi-mono-集成">#</a> pi-mono 集成</h2><p>OpenSoul 复用 pi-mono 代码库的部分内容（模型/工具），但<strong>会话管理、设备发现和工具连接由 OpenSoul 负责</strong>。</p><ul><li>无 pi-coding 智能体运行时。</li><li>不读取 <code>~/.pi/agent</code> 或 <code>&lt;workspace&gt;/.pi</code> 设置。</li></ul><h2 id="会话" tabindex="-1"><a class="header-anchor" href="#会话">#</a> 会话</h2><p>会话记录以 JSONL 格式存储在：</p><ul><li><code>~/.opensoul/agents/&lt;agentId&gt;/sessions/&lt;SessionId&gt;.jsonl</code></li></ul><p>会话 ID 是稳定的，由 OpenSoul 选择。 <strong>不</strong>读取旧版 Pi/Tau 会话文件夹。</p><h2 id="流式传输中的引导" tabindex="-1"><a class="header-anchor" href="#流式传输中的引导">#</a> 流式传输中的引导</h2><p>当队列模式为 <code>steer</code> 时，入站消息会注入当前运行。 队列在<strong>每次工具调用后</strong>检查；如果存在排队消息，当前助手消息的剩余工具调用将被跳过（工具结果显示错误&quot;Skipped due to queued user message.&quot;），然后在下一个助手响应前注入排队的用户消息。</p><p>当队列模式为 <code>followup</code> 或 <code>collect</code> 时，入站消息会保留到当前轮次结束，然后使用排队的载荷开始新的智能体轮次。参见 <a href="/docs/concepts/queue">队列</a> 了解模式 + 防抖/上限行为。</p><p>分块流式传输在助手块完成后立即发送；默认为<strong>关闭</strong>（<code>agents.defaults.blockStreamingDefault: &quot;off&quot;</code>）。 通过 <code>agents.defaults.blockStreamingBreak</code> 调整边界（<code>text_end</code> 与 <code>message_end</code>；默认为 text_end）。 使用 <code>agents.defaults.blockStreamingChunk</code> 控制软块分块（默认 800–1200 字符；优先段落分隔，其次换行；最后是句子）。 使用 <code>agents.defaults.blockStreamingCoalesce</code> 合并流式块以减少单行刷屏（发送前基于空闲的合并）。非 Telegram 渠道需要显式设置 <code>*.blockStreaming: true</code> 以启用分块回复。 工具启动时发出详细工具摘要（无防抖）；Control UI 在可用时通过智能体事件流式传输工具输出。 更多详情：<a href="/docs/concepts/streaming">流式传输 + 分块</a>。</p><h2 id="模型引用" tabindex="-1"><a class="header-anchor" href="#模型引用">#</a> 模型引用</h2><p>配置中的模型引用（例如 <code>agents.defaults.model</code> 和 <code>agents.defaults.models</code>）通过在<strong>第一个</strong> <code>/</code> 处分割来解析。</p><ul><li>配置模型时使用 <code>provider/model</code>。</li><li>如果模型 ID 本身包含 <code>/</code>（OpenRouter 风格），请包含提供商前缀（例如：<code>openrouter/moonshotai/kimi-k2</code>）。</li><li>如果省略提供商，OpenSoul 将输入视为别名或<strong>默认提供商</strong>的模型（仅在模型 ID 中没有 <code>/</code> 时有效）。</li></ul><h2 id="配置-最小" tabindex="-1"><a class="header-anchor" href="#配置-最小">#</a> 配置（最小）</h2><p>至少需要设置：</p><ul><li><code>agents.defaults.workspace</code></li><li><code>channels.whatsapp.allowFrom</code>（强烈建议）</li></ul><hr><p><em>下一篇：<a href="/docs/channels/group-messages">群聊</a></em> 🦞</p>',41)])])}const g=o(c,[["render",t]]);export{u as __pageData,g as default};
